import json
from dataclasses import dataclass, field
from typing import Any, Callable

from openai import OpenAI

client = OpenAI()


@dataclass
class Tool:
    name: str
    description: str
    parameters: dict           # JSON Schema object
    fn: Callable[..., Any]     # the actual implementation

    def to_openai_spec(self) -> dict:
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters,
            },
        }


def react_loop(
    task: str,
    tools: list[Tool],
    model: str = "claude-opus-4-8",
    max_steps: int = 15,
    system_prompt: str = "",
) -> str:
    tool_map = {t.name: t for t in tools}
    messages = [
        {"role": "system", "content": system_prompt or (
            "You are a back-office automation agent. "
            "Use tools to complete the task. "
            "Call FINAL_ANSWER when the task is fully done."
        )},
        {"role": "user", "content": task},
    ]
    for step in range(max_steps):
        response = client.chat.completions.create(
            model=model,
            messages=messages,
            tools=[t.to_openai_spec() for t in tools],
            tool_choice="auto",
        )
        msg = response.choices[0].message
        messages.append(msg)  # assistant turn

        if not msg.tool_calls:
            # No tool call → LLM produced a text answer
            return msg.content or ""

        # Execute all tool calls in this step
        for tc in msg.tool_calls:
            fn_name = tc.function.name
            args = json.loads(tc.function.arguments)
            if fn_name not in tool_map:
                result = f"Error: unknown tool '{fn_name}'"
            else:
                try:
                    result = tool_map[fn_name].fn(**args)
                except Exception as exc:
                    result = f"Error: {exc}"
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": json.dumps(result) if not isinstance(result, str) else result,
            })
    raise RuntimeError(f"Agent did not finish within {max_steps} steps")

